const labels = {
  instagram: 'Instagram', linkedin: 'LinkedIn', whatsapp: 'WhatsApp', gmail: 'Gmail', github: 'GitHub', git: 'Git',
  java: 'Java', visualbasic: 'Visual Basic', html5: 'HTML', css3: 'CSS', javascript: 'JavaScript',
  vscode: 'Visual Studio Code', figma: 'Figma', mysql: 'MySQL'
}

// Bikin 1 SVG utuh sebagai string, baru di-inject sekali lewat v-html.
// Ini jauh lebih stabil daripada nyuntik path satu-satu ke <svg> yang sudah ada.
const brandSvg = computed(() => {
  if (!props.brand || !brandIcons[props.brand]) return ''
  const icon = brandIcons[props.brand]
  const innerSize = icon.chip ? Math.round(props.size * 0.62) : props.size
  return `<svg xmlns="http://www.w3.org/2000/svg" width="${innerSize}" height="${innerSize}" viewBox="${icon.viewBox}">${icon.body}</svg>`
})
</script>

<template>
  <!-- Ikon UI outline (Lucide) -->
  <svg
    v-if="name && lineIcons[name]"
    :width="size" :height="size" viewBox="0 0 24 24"
    fill="none" stroke="currentColor" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"
    v-html="lineIcons[name]"
  ></svg>

  <!-- Logo brand asli -->
  <span
    v-else-if="brand && brandIcons[brand]"
    class="brand-wrap"
    :class="{ chip: brandIcons[brand].chip }"
    :style="{ width: size + 'px', height: size + 'px' }"
    :title="labels[brand]"
    :aria-label="labels[brand]"
    v-html="brandSvg"
  ></span>
</template>

<style scoped>
.brand-wrap {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}

.brand-wrap.chip {
  border-radius: 12px;
  background: #f5f7fb;
}
</style>